[CmdletBinding()]param()
$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');. (Join-Path $root 'scripts/security/Test-ProjectRelativePath.ps1');. (Join-Path $root 'scripts/records/Get-SurfaceRegistry.ps1')
$work=Join-Path ([IO.Path]::GetTempPath()) ('runtime-specialist-'+[guid]::NewGuid().ToString('N'));$fail=[Collections.Generic.List[string]]::new();function Assert($ok,$message){if(-not $ok){$fail.Add($message)}}
try{$project=New-TypedStudioFixture -RootPath $work -Name 'backend' -Surfaces @('backend-api','approved-refactor','performance') -Approved;Assert (Test-ProjectRelativePath $project 'src/server/api.ps1' -AllowGlob).valid 'project relative path rejected.';Assert (-not(Test-ProjectRelativePath $project '../escape').valid) 'traversal accepted.';Assert (-not(Test-ProjectRelativePath $project 'C:\escape').valid) 'absolute path accepted.';$registry=Get-SurfaceRegistry -Surface @('backend-api');Assert ($registry.selected.Count -eq 1) 'surface registry did not select backend.';try{Get-SurfaceRegistry -Surface @('unknown') -RequireKnown|Out-Null;Assert $false 'unknown surface accepted.'}catch{Assert ($_.Exception.Message -match 'Unknown surface') 'unknown surface error not targeted.'};$plan=& (Join-Path $root 'scripts/Resolve-SpecialistPlan.ps1') -ProjectRoot $project -OutputPath (Join-Path $project '.studio/reports/specialist-plan.json');Assert ($plan.schemaVersion -eq 2) 'DAG schema missing.';Assert ($plan.selected -contains 'refactor-engineer') 'refactor routing missing.';Assert ($plan.selected -contains 'performance-auditor') 'performance routing missing.';Assert (Test-Path (Join-Path $project '.studio/runtime/assignments/backend-builder.json')) 'assignment missing.'}finally{if(Test-Path $work){Remove-Item -LiteralPath $work -Recurse -Force}}
if($fail.Count){$fail|ForEach-Object{Write-Error $_};exit 1};Write-Host 'Runtime and specialist orchestration fixtures passed: registry, paths, DAG, routing, and assignments; host runtime unverified.'
